// We're DIRECTLY downstream of Telegram Trigger via Is Photo? (which preserves binary).
const meta = $input.first().binary?.data;
if (!meta) {
  throw new Error('Telegram Trigger item has no binary.data. Enable additionalFields.download=true.');
}
const mime = meta.mimeType || 'image/jpeg';

let base64;
try {
  const buffer = await $helpers.getBinaryDataBuffer(0, 'data');
  base64 = buffer.toString('base64');
} catch (err) {
  if (typeof meta.data === 'string' && meta.data.length > 500) {
    base64 = meta.data;
  } else {
    throw new Error('Could not read image binary: ' + (err?.message || 'unknown'));
  }
}

return [{
  json: {
    caption: $json.message.caption || '',
    chat_id: $json.message.chat.id,
    message_id: $json.message.message_id,
    data_url: `data:${mime};base64,${base64}`
  }
}];

const raw = $input.first().json?.choices?.[0]?.message?.content || '';
const cleaned = raw.replace(/```json\n?|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{ json: { _error: 'Could not parse vision output', raw } }];
}

if (typeof parsed.amount !== 'number' || parsed.amount <= 0 || !parsed.transaction_type) {
  return [{ json: { _error: 'No valid amount detected from photo', parsed } }];
}

const ctx = $('Photo To Base64').first().json;

const payload = {
  transaction_type: parsed.transaction_type,
  amount: parsed.amount,
  currency: parsed.currency || 'IDR',
  transaction_date: parsed.transaction_date || new Date().toISOString().slice(0, 10),
  merchant_name: parsed.merchant_name || null,
  item_name: parsed.item_name || null,
  category: parsed.category || null,
  payment_method: parsed.payment_method || null,
  invoice_number: parsed.invoice_number || null,
  notes: parsed.notes || ctx.caption || null,
  source_channel: 'telegram',
  source_reference: `tg:${ctx.chat_id}:${ctx.message_id}:photo`,
  confidence_score: typeof parsed.confidence_score === 'number' ? parsed.confidence_score : 0.6,
  category_confidence: typeof parsed.confidence_score === 'number' ? parsed.confidence_score : null,
  parsed_status: (parsed.confidence_score && parsed.confidence_score >= 0.8) ? 'parsed' : 'pending'
};

return [{ json: payload }];

const raw = $input.first().json?.choices?.[0]?.message?.content || '';
const cleaned = raw.replace(/```json\n?|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{ json: { _error: 'Could not parse LLM output', raw, cleaned } }];
}

if (!parsed || typeof parsed.amount !== 'number' || !parsed.transaction_type) {
  return [{ json: { _error: 'LLM output missing required fields', parsed } }];
}

const chatId = $('Telegram Trigger').item.json.message.chat.id;
const msgId  = $('Telegram Trigger').item.json.message.message_id;

const payload = {
  transaction_type: parsed.transaction_type,
  amount: parsed.amount,
  currency: parsed.currency || 'IDR',
  transaction_date: new Date().toISOString().slice(0, 10),
  merchant_name: parsed.merchant_name || null,
  item_name: parsed.item_name || null,
  category: parsed.category || null,
  payment_method: parsed.payment_method || null,
  notes: parsed.notes || null,
  source_channel: 'telegram',
  source_reference: `tg:${chatId}:${msgId}`,
  confidence_score: typeof parsed.confidence_score === 'number' ? parsed.confidence_score : 0.7,
  parsed_status: 'parsed'
};

return [{ json: payload }];

const user_id = $input.first().json.user_id;
const photoPayload = $('Build Photo Payload').first()?.json;
const textPayload  = $('Build Payload').first()?.json;
const base = (photoPayload && !photoPayload._error) ? photoPayload : textPayload;
if (!base) throw new Error('No payload to enrich');
return [{ json: { ...base, user_id } }];

